import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Transaction {
  date: string;
  points: number;
  description: string;
}

interface Reward {
  reward: string;
  pointsRequired: number;
}

interface LoyaltyData {
  balance: number;
  recentTransactions: Transaction[];
  availableRewards: Reward[];
}

export default function Widget() {
  const loyaltyData = response.data as LoyaltyData;
  const { balance, recentTransactions, availableRewards } = loyaltyData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#303030', color: '#FFFFFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FFC107' }}>
              Loyalty Points
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {balance.toLocaleString()} pts
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#424242' }} />

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Recent Transactions
            </Typography>
            {recentTransactions.map((transaction, index) => (
              <Stack key={index} direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
                <Typography variant="body2">{transaction.description}</Typography>
                <Typography variant="body2">{transaction.points} pts</Typography>
              </Stack>
            ))}
          </Box>

          <Divider sx={{ bgcolor: '#424242' }} />

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Available Rewards
            </Typography>
            {availableRewards.map((reward, index) => (
              <Chip
                key={index}
                label={`${reward.reward} - ${reward.pointsRequired} pts`}
                sx={{ bgcolor: '#424242', color: '#FFC107', fontSize: '12px', mb: 0.5 }}
              />
            ))}
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
